import timeimport mujocoimport mujoco.viewermodel=mujoco.MjModel.from_xml_path("/Users/biswargabidittamuli/InsectsCADModels/SeparatedInsects/AnoplophoraMalaciaca/am.xml")data=mujoco.MjData(model)print("Model loaded successfully")print("Number of bodies: ",model.nbody)print("Number of joints",model.njnt)print("Number of geometries: ",model.ngeom)print(model.nmesh)with mujoco.viewer.launch_passive(model,data) as viewer:    start=time.time()    while viewer.is_running():        #step the physics by one time step dt        mujoco.mj_step(model,data)        viewer.sync()            end=time.time()    print(start-end, "seconds")        